var deactivateDeployments = async (repo, environmentPrefix) => {
    const githubEventName = context.eventName;
    const environment = githubEventName === 'pull_request'
        ? `${environmentPrefix || 'PR-'}${context.payload.pull_request.number}`
        : `${environmentPrefix || 'ACTION-'}${dayjs().format('DD-MM-YYYY-hh:mma')}`;
    const deployments = await getGithubClient().rest.repos.listDeployments({
        repo: repo.repo,
        owner: repo.owner,
        environment
    });
    const existing = deployments.data.length;
    if (existing < 1) {
        console.log('No exiting deployments found for pull request');
        return;
    }
    for (const deployment of deployments.data) {
        console.log(`Deactivating existing deployment - ${deployment.id}`);
        await getGithubClient().rest.repos.createDeploymentStatus({
            ...repo,
            deployment_id: deployment.id,
            state: 'inactive'
        });
    }
};

var deleteDeployments = async (repo, environmentPrefix) => {
    const githubEventName = context.eventName;
    const environment = githubEventName === 'pull_request'
        ? `${environmentPrefix || 'PR-'}${context.payload.pull_request.number}`
        : `${environmentPrefix || 'ACTION-'}${dayjs().format('DD-MM-YYYY-hh:mma')}`;
    const deployments = await getGithubClient().rest.repos.listDeployments({
        ...repo,
        environment: environment,
        per_page: 100
    });
    console.log(JSON.stringify(deployments));
    if (deployments.data.length <= 0) {
        console.log('No exiting deployments found for pull request');
        return;
    }
    for (const deployment of deployments.data) {
        console.log(`Deleting existing deployment - ${deployment.id}`);
        await getGithubClient().rest.repos.deleteDeployment({
            ...repo,
            deployment_id: deployment.id
        });
    }
};

